/**
 * Memoizes a pure function with an optional max cache size (LRU eviction).
 * Args must be JSON-serializable.
 * @param {Function} fn - Pure function to memoize.
 * @param {Object} [options]
 * @param {number} [options.maxSize=Infinity] - Max number of cached entries.
 */
const memoize = (fn, { maxSize = Infinity } = {}) => {
  const cache = new Map();

  return (...args) => {
    const key = (() => {
      try { return JSON.stringify(args); }
      catch (_) { return null; }
    })();

    if (key !== null && cache.has(key)) {
      const cached = cache.get(key);
      cache.delete(key);
      cache.set(key, cached); // move to end (most recently used)
      return cached;
    }

    const result = fn(...args);

    if (key !== null) {
      if (cache.size >= maxSize) {
        const oldestKey = cache.keys().next().value;
        cache.delete(oldestKey); // evict least recently used
      }
      cache.set(key, result);
    }

    return result;
  };
};
```

Still `const`, factory still pure. `Map` preserves insertion order so the first key is always the oldest — a clean LRU without extra data structures:

```js
const cachedFn = memoize(expensiveFn, { maxSize: 100 });
```
